 1	import React, { FC, PropsWithChildren, ReactNode, SyntheticEvent } from 'react';
 2	
 3	import { Button, Flex, Tooltip } from '@patternfly/react-core';
 4	import { PencilAltIcon } from '@patternfly/react-icons';
 5	
 6	type EditButtonWithTooltipProps = PropsWithChildren<{
 7	  isEditable: boolean;
 8	  onEditClick: () => void;
 9	  testId: string;
10	  tooltipContent?: ReactNode;
11	}>;
12	
13	const EditButtonWithTooltip: FC<EditButtonWithTooltipProps> = ({
14	  children,
15	  isEditable,
16	  onEditClick,
17	  testId,
18	  tooltipContent,
19	}) => {
20	  const EditButton = () => (
21	    <Button
22	      onClick={(e: SyntheticEvent<HTMLButtonElement>) => {
23	        e.stopPropagation();
24	        onEditClick?.();
25	      }}
26	      data-test-id={testId}
27	      isDisabled={!isEditable}
28	      isInline
29	      variant="link"
30	    >
31	      <Flex>
32	        {children}
33	        <PencilAltIcon className="co-icon-space-l" />
34	      </Flex>
35	    </Button>
36	  );
37	
38	  if (!isEditable && tooltipContent) {
39	    return (
40	      <Tooltip content={tooltipContent}>
41	        <span>
42	          <EditButton />
43	        </span>
44	      </Tooltip>
45	    );
46	  }
47	
48	  return <EditButton />;
49	};
50	
51	export default EditButtonWithTooltip;

